329→public fun ASTNode.lineIndent(): String {
330→    var leaf = this.prevLeaf()
331→    while (leaf != null) {
332→        if (leaf.elementType == WHITE_SPACE && leaf.textContains('\n')) {
333→            return leaf.text.substring(leaf.text.lastIndexOf('\n') + 1)
334→        }
335→        leaf = leaf.prevLeaf()
336→    }
337→    return ""
338→}
