368→/**
369→ * Verifies that a leaf containing a newline exist in the closed range [from] - [to]. Also, returns true in case any of
370→ * the boundary nodes [from] or [to] contains a newline.
371→ */
372→public fun hasNewLineInClosedRange(
373→    from: ASTNode,
374→    to: ASTNode,
375→): Boolean =
376→    from.isWhiteSpaceWithNewline() ||
377→        leavesInOpenRange(from, to).any { it.textContains('\n') } ||
378→        to.isWhiteSpaceWithNewline()
379→
380→/**
381→ * Verifies that no leaf contains a newline in the closed range [from] - [to]. Also, the boundary nodes [from] and [to]
382→ * should not contain a newline.
383→ */
384→public fun noNewLineInClosedRange(
385→    from: ASTNode,
386→    to: ASTNode,
387→): Boolean =
388→    !from.isWhiteSpaceWithNewline() &&
389→        noNewLineInOpenRange(from, to) &&
390→        !to.isWhiteSpaceWithNewline()
391→
392→/**
393→ * Verifies that no leaf contains a newline in the open range [from] - [to]. This means that the boundary nodes are excluded from the range
394→ * in case they would happen to be a leaf node. In case [from] is a [CompositeElement] than the first leaf node in the sequence is the first
395→ * leaf node in this [CompositeElement]. In case [to] is a [CompositeElement] than the last node in the sequence is the last leaf node prior
396→ * to this [CompositeElement].
397→ */
398→public fun noNewLineInOpenRange(
399→    from: ASTNode,
400→    to: ASTNode,
401→): Boolean = leavesInOpenRange(from, to).none { it.textContains('\n') }
402→
403→/**
404→ * Creates a sequence of leaf nodes in the open range [from] - [to]. This means that the boundary nodes are excluded
405→ * from the range in case they would happen to be a leaf node. In case [from] is a [CompositeElement] than the first
406→ * leaf node in the sequence is the first leaf node in this [CompositeElement]. In case [to] is a [CompositeElement]
407→ * than the last node in the sequence is the last leaf node prior to this [CompositeElement].
408→ */
409→public fun leavesInOpenRange(
410→    from: ASTNode,
411→    to: ASTNode,
412→): Sequence<ASTNode> =
413→    from
414→        .leaves()
415→        .takeWhile { it != to && it != to.firstChildNode }
416→
417→public fun ASTNode.isValOrVarKeyword(): Boolean = elementType == VAL_KEYWORD || elementType == VAR_KEYWORD || elementType == VARARG_KEYWORD
418→
419→/**
420→ * Creates a sequences of leaves including the [ASTNode] in case it is a [LeafElement] itself. By default, the leaves are traversed in
421→ * forward order. Setting [forward] to `false` changes this to traversal in backward direction.
422→ */
423→public fun ASTNode.leavesIncludingSelf(forward: Boolean = true): Sequence<ASTNode> {
424→    val sequence =
425→        if (isLeaf()) {
426→            sequenceOf(this)
427→        } else {
428→            emptySequence()
429→        }
430→    return sequence.plus(leaves(forward))
431→}
