{"file_path":"/project/ktlint-rule-engine/src/test/kotlin/com/pinterest/ktlint/rule/engine/api/KtLintRuleEngineFormatRerunTest.kt","content":"package com.pinterest.ktlint.rule.engine.api

import com.pinterest.ktlint.rule.engine.core.api.ElementType.FILE
import com.pinterest.ktlint.rule.engine.core.api.ElementType.REGULAR_STRING_PART
import com.pinterest.ktlint.rule.engine.core.api.Rule
import com.pinterest.ktlint.rule.engine.core.api.Rule.VisitorModifier.RunAsLateAsPossible
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import org.assertj.core.api.Assertions.assertThat
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.LeafElement
import org.junit.jupiter.api.Test
import java.util.concurrent.atomic.AtomicInteger

class KtLintRuleEngineFormatRerunTest {
    @Test
    fun `Format reruns when new auto-correctable violations are introduced by rules that run late`() {
        val formatRuns = AtomicInteger(0)

        val ruleThatRunsEarlyAndFixesBToC =
            RuleProvider {
                object : Rule(RuleId("test:fix-b-to-c"), About()) {
                    override fun beforeVisitChildNodes(
                        node: ASTNode,
                        autoCorrect: Boolean,
                        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
                    ) {
                        if (autoCorrect && node.elementType == FILE) {
                            // Count only the actual format pass; not the follow-up lint pass.
                            formatRuns.incrementAndGet()
                        }
                        if (node.elementType == REGULAR_STRING_PART && node.text == "b") {
                            emit(node.startOffset, "Value 'b' is not allowed", true)
                            if (autoCorrect) {
                                (node as LeafElement).rawReplaceWithText("c")
                            }
                        }
                    }
                }
            }

        val ruleThatRunsLateAndIntroducesB =
            RuleProvider {
                object : Rule(
                    ruleId = RuleId("test:introduce-b"),
                    about = About(),
                    visitorModifiers = setOf(RunAsLateAsPossible),
                ) {
                    override fun beforeVisitChildNodes(
                        node: ASTNode,
                        autoCorrect: Boolean,
                        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
                    ) {
                        if (node.elementType == REGULAR_STRING_PART && node.text == "a") {
                            emit(node.startOffset, "Value 'a' should be replaced with 'b'", true)
                            if (autoCorrect) {
                                (node as LeafElement).rawReplaceWithText("b")
                            }
                        }
                    }
                }
            }

        val callbacks = mutableListOf<Pair<LintError, Boolean>>()
        val formattedCode =
            KtLintRuleEngine(
                ruleProviders =
                    setOf(
                        ruleThatRunsEarlyAndFixesBToC,
                        ruleThatRunsLateAndIntroducesB,
                    ),
            ).format(
                Code.fromSnippet("val foo = \"a\""),
            ) { e, corrected ->
                callbacks.add(e to corrected)
            }

        assertThat(formattedCode).isEqualTo("val foo = \"c\"")
        // Ensure that format was rerun at least once (first run introduces "b", second run fixes it).
        assertThat(formatRuns.get()).isEqualTo(2)
        // Ensure that no remaining auto-correctable errors are reported.
        assertThat(callbacks.filter { (e, corrected) -> e.canBeAutoCorrected && !corrected }).isEmpty()
    }

    @Test
    fun `Format is rerun at most 3 times to prevent endless loops`() {
        val formatRuns = AtomicInteger(0)

        val ruleThatRunsEarlyAndFixesBToA =
            RuleProvider {
                object : Rule(RuleId("test:fix-b-to-a"), About()) {
                    override fun beforeVisitChildNodes(
                        node: ASTNode,
                        autoCorrect: Boolean,
                        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
                    ) {
                        if (autoCorrect && node.elementType == FILE) {
                            // Count only the actual format pass; not the follow-up lint pass.
                            formatRuns.incrementAndGet()
                        }
                        if (node.elementType == REGULAR_STRING_PART && node.text == "b") {
                            emit(node.startOffset, "Value 'b' should be replaced with 'a'", true)
                            if (autoCorrect) {
                                (node as LeafElement).rawReplaceWithText("a")
                            }
                        }
                    }
                }
            }

        val ruleThatRunsLateAndFixesAToB =
            RuleProvider {
                object : Rule(
                    ruleId = RuleId("test:fix-a-to-b"),
                    about = About(),
                    visitorModifiers = setOf(RunAsLateAsPossible),
                ) {
                    override fun beforeVisitChildNodes(
                        node: ASTNode,
                        autoCorrect: Boolean,
                        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
                    ) {
                        if (node.elementType == REGULAR_STRING_PART && node.text == "a") {
                            emit(node.startOffset, "Value 'a' should be replaced with 'b'", true)
                            if (autoCorrect) {
                                (node as LeafElement).rawReplaceWithText("b")
                            }
                        }
                    }
                }
            }

        val formattedCode =
            KtLintRuleEngine(
                ruleProviders =
                    setOf(
                        ruleThatRunsEarlyAndFixesBToA,
                        ruleThatRunsLateAndFixesAToB,
                    ),
            ).format(Code.fromSnippet("val foo = \"b\""))

        // Total number of format runs equals 1 initial run + 3 reruns.
        assertThat(formatRuns.get()).isEqualTo(4)
        // Last run ends with "b" as the late rule always flips the value back.
        assertThat(formattedCode).isEqualTo("val foo = \"b\"")
    }
}
