        code: Code,
        callback: (LintError, Boolean) -> Unit = { _, _ -> },
    ): String {
        LOGGER.debug { "Starting with formatting file '${code.fileNameOrStdin()}'" }

        data class FormatResult(
            val formattedCode: String,
            val errors: List<Pair<LintError, Boolean>>,
            val foundAutoCorrectableViolations: Boolean,
        )

        fun formatOnce(codeToFormat: Code): FormatResult {
            val hasUTF8BOM = codeToFormat.content.startsWith(UTF8_BOM)
            val ruleExecutionContext = createRuleExecutionContext(this, codeToFormat)

            var tripped = false
            var foundAutoCorrectableViolations = false
            val errors = mutableSetOf<Pair<LintError, Boolean>>()
            val visitorProvider = VisitorProvider(ruleExecutionContext.ruleProviders)

            visitorProvider
                .visitor()
                .invoke { rule ->
                    ruleExecutionContext.executeRule(rule, true) { offset, errorMessage, canBeAutoCorrected ->
                        tripped = true
                        if (canBeAutoCorrected) {
                            foundAutoCorrectableViolations = true
                            /**
                             * Rebuild the suppression locator after each change in the AST as the offsets of the
                             * suppression hints might have changed.
                             */
                            ruleExecutionContext.rebuildSuppressionLocator()
                        }
                        val (line, col) = ruleExecutionContext.positionInTextLocator(offset)
                        errors.add(
                            Pair(
                                LintError(line, col, rule.ruleId, errorMessage, canBeAutoCorrected),
                                // It is assumed that a rule that emits that an error can be autocorrected, also
                                // does correct the error.
                                canBeAutoCorrected,
                            ),
                        )
                        // In trace mode report the violation immediately. The order in which violations are actually found might be different
                        // from the order in which they are reported. For debugging purposes it cn be helpful to know the exact order in which
                        // violations are being solved.
                        LOGGER.trace {
                            "Format violation: ${codeToFormat.fileNameOrStdin()}:$line:$col: $errorMessage (${rule.ruleId})" +
                                canBeAutoCorrected.ifFalse { " [cannot be autocorrected]" }
                        }
                    }
                }

            if (tripped) {
                visitorProvider
                    .visitor()
                    .invoke { rule ->
                        ruleExecutionContext.executeRule(
                            rule,
                            false,
                        ) { offset, errorMessage, canBeAutoCorrected ->
                            val (line, col) = ruleExecutionContext.positionInTextLocator(offset)
                            errors.add(
                                Pair(
                                    LintError(line, col, rule.ruleId, errorMessage, canBeAutoCorrected),
                                    // It is assumed that a rule only corrects an error after it has emitted an
                                    // error and indicating that it actually can be autocorrected.
                                    false,
                                ),
                            )
                        }
                    }
            }

            val formattedCode =
                if (!foundAutoCorrectableViolations) {
                    codeToFormat.content
                } else {
                    val formatted =
                        ruleExecutionContext
                            .rootNode
                            .text
                            .replace("\n", ruleExecutionContext.determineLineSeparator(codeToFormat.content))
                    if (hasUTF8BOM) {
                        UTF8_BOM + formatted
                    } else {
                        formatted
                    }
                }

            return FormatResult(
                formattedCode = formattedCode,
                errors = errors.sortedWith { (l), (r) -> if (l.line != r.line) l.line - r.line else l.col - r.col },
                foundAutoCorrectableViolations = foundAutoCorrectableViolations,
            )
        }

        // Repeat format until no more violations are found that can be autocorrected.
        // To prevent infinite reruns, execute at most 3 reruns.
        var codeToFormat = code
        var lastResult: FormatResult
        var reruns = 0
        do {
            lastResult = formatOnce(codeToFormat)
            if (!lastResult.foundAutoCorrectableViolations || reruns == 3) {
                break
            }
            reruns++
            codeToFormat = codeToFormat.copy(content = lastResult.formattedCode)
        } while (true)

        lastResult
            .errors
            .forEach { (e, corrected) -> callback(e, corrected) }

        LOGGER.debug("Finished with formatting file '${code.fileNameOrStdin()}'")
        return lastResult.formattedCode
    }"}

